mapper.select:
SELECT * FROM ( SELECT A1.*, ROW_NUMBER() OVER () AS PAGEINDEX FROM ( SELECT request.REQUEST_NO AS requestNo, request.REQUEST_NO AS requestOrgNo, requestMapping.OBJECT_NO AS drawingNo, requestMapping.OBJECT_NM AS drawingNm, requestMapping.REV_NO AS revNo, FN_GET_CD_NM('requestPurpose', request.REQUEST_PURPOSE, #{sessionLang}) AS requestPurposeNm, CASE WHEN deployInfo.DEPLOY_NORMAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.normalArea' AND lang.LANG_TYPE = 'ko') WHEN deployInfo.DEPLOY_SPECIAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.specialArea' AND lang.LANG_TYPE = 'ko') ELSE (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.viewing' AND lang.LANG_TYPE = 'ko') END AS distributeTypeNm, companyUser.USER_CD AS companyUserCd, companyUser.USER_NM AS companyUserNm, ( SELECT USER_CD FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ORIGINAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS purchaserUserCd, ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ORIGINAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS purchaserUserNm, ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS deployUserNm, request.INSERT_DT AS requestDt, request.APPROVAL_DT AS approvalDt, FN_GET_CD_NM('requestStatusCd', request.STATUS_CD, #{sessionLang}) || '(' || ( SELECT COUNT(*) FROM DOCS_REQUEST_MAPPING tmp WHERE tmp.REQUEST_NO = request.REQUEST_NO ) || ')' AS statusNm, request.STATUS_CD AS statusCd, requestMapping.TOTAL_PAGE_NO AS totalPageNo, requestMapping.CURRENT_PAGE_NO AS currentPageNo, request.REQUEST_PURPOSE AS requestPurpose, request.VENDOR_ACCEPT_YN AS vendorAcceptYn, FN_GET_CD_NM('vendorAcceptYn', request.VENDOR_ACCEPT_YN, #{sessionLang}) AS vendorAcceptNm, request.VENDOR_ACCEPT_USER_CD AS vendorAcceptUserCd, (SELECT acceptUser.USER_NM FROM DOCS_USER acceptUser WHERE acceptUser.USER_CD = request.VENDOR_ACCEPT_USER_CD) AS vendorAcceptUserNm, request.VENDOR_ACCEPT_DT AS vendorAcceptDt FROM DOCS_REQUEST request INNER JOIN ( SELECT tempMapping.REQUEST_NO, MAX(tempMapping.OBJECT_ID) AS OBJECT_ID FROM DOCS_REQUEST_MAPPING tempMapping WHERE 1=1
AND OBJECT_NO ILIKE '%' || TRIM(#{drawingNo}) || '%'
AND OBJECT_NM ILIKE '%' || #{drawingNm} || '%'
GROUP BY REQUEST_NO ) tempMapping ON tempMapping.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_REQUEST_MAPPING requestMapping ON requestMapping.REQUEST_NO = tempMapping.REQUEST_NO AND requestMapping.OBJECT_ID = tempMapping.OBJECT_ID INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_USER companyUser ON companyUser.USER_CD = deployInfo.DEPLOY_USER_CD WHERE request.OBJECT_TYPE = 'DRAWING' AND request.REQUEST_TYPE = 'DISTRIBUTION' AND request.DEPLOY_COMPANY_CD = #{sessionUser.companyCd}
AND request.INSERT_DT BETWEEN TO_DATE(#{requestStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{requestEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
ORDER BY requestDt DESC, requestNo DESC
ORDER BY ${sortColumn} ${order}, requestNo ${order}
) A1 WHERE 1=1
AND requestNo = #{requestNo}
AND purchaserUserCd = #{purchaserUserCd}
AND companyUserCd = #{companyUserCd}
AND statusCd = #{statusCd}
AND requestPurpose = #{requestPurpose}
) B1 WHERE PAGEINDEX >= #{start}
AND PAGEINDEX <= #{end}

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT A1.* FROM ( SELECT request.REQUEST_NO AS requestNo, request.REQUEST_NO AS requestOrgNo, requestMapping.OBJECT_NO AS drawingNo, requestMapping.OBJECT_NM AS drawingNm, requestMapping.REV_NO AS revNo, FN_GET_CD_NM('requestPurpose', request.REQUEST_PURPOSE, #{sessionLang}) AS requestPurposeNm, CASE WHEN deployInfo.DEPLOY_NORMAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.normalArea' AND lang.LANG_TYPE = 'ko') WHEN deployInfo.DEPLOY_SPECIAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.specialArea' AND lang.LANG_TYPE = 'ko') ELSE (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.viewing' AND lang.LANG_TYPE = 'ko') END AS distributeTypeNm, companyUser.USER_CD AS companyUserCd, companyUser.USER_NM AS companyUserNm, ( SELECT USER_CD FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ORIGINAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS purchaserUserCd, ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ORIGINAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS purchaserUserNm, ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS deployUserNm, request.INSERT_DT AS requestDt, request.APPROVAL_DT AS approvalDt, FN_GET_CD_NM('requestStatusCd', request.STATUS_CD, #{sessionLang}) || '(' || ( SELECT COUNT(*) FROM DOCS_REQUEST_MAPPING tmp WHERE tmp.REQUEST_NO = request.REQUEST_NO ) || ')' AS statusNm, request.STATUS_CD AS statusCd, requestMapping.TOTAL_PAGE_NO AS totalPageNo, requestMapping.CURRENT_PAGE_NO AS currentPageNo, request.REQUEST_PURPOSE AS requestPurpose, request.VENDOR_ACCEPT_YN AS vendorAcceptYn, FN_GET_CD_NM('vendorAcceptYn', request.VENDOR_ACCEPT_YN, #{sessionLang}) AS vendorAcceptNm, request.VENDOR_ACCEPT_USER_CD AS vendorAcceptUserCd, (SELECT acceptUser.USER_NM FROM DOCS_USER acceptUser WHERE acceptUser.USER_CD = request.VENDOR_ACCEPT_USER_CD) AS vendorAcceptUserNm, request.VENDOR_ACCEPT_DT AS vendorAcceptDt FROM DOCS_REQUEST request INNER JOIN ( SELECT tempMapping.REQUEST_NO, MAX(tempMapping.OBJECT_ID) AS OBJECT_ID FROM DOCS_REQUEST_MAPPING tempMapping WHERE 1=1
AND OBJECT_NO ILIKE '%' || TRIM(#{drawingNo}) || '%'
AND OBJECT_NM ILIKE '%' || #{drawingNm} || '%'
GROUP BY REQUEST_NO ) tempMapping ON tempMapping.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_REQUEST_MAPPING requestMapping ON requestMapping.REQUEST_NO = tempMapping.REQUEST_NO AND requestMapping.OBJECT_ID = tempMapping.OBJECT_ID INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_USER companyUser ON companyUser.USER_CD = deployInfo.DEPLOY_USER_CD WHERE request.OBJECT_TYPE = 'DRAWING' AND request.REQUEST_TYPE = 'DISTRIBUTION' AND request.DEPLOY_COMPANY_CD = #{sessionUser.companyCd}
AND request.INSERT_DT BETWEEN TO_DATE(#{requestStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{requestEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
) A1 WHERE 1=1
AND requestNo = #{requestNo}
AND purchaserUserCd = #{purchaserUserCd}
AND companyUserCd = #{companyUserCd}
AND statusCd = #{statusCd}
AND requestPurpose = #{requestPurpose}
) B1

SELECT *
FROM (
		 SELECT drawing.*
		 FROM DOCS_DRAWING drawing
		 WHERE DRAWING_NO = #{drawingNo}
		   AND REV_NO = #{revNo}
		 ORDER BY DRAWING_REV DESC, REV_NO DESC
	 ) drawing
